import Typewriter from "typewriter-effect"
import styled from "styled-components"

import { InView, useInView } from 'react-intersection-observer';

const Projects = ({ id }) => {
  return (
    <ProjectsContainer id={id}>
      <InView triggerOnce>
        {({ inView, ref, entry }) => (
          <SectionHeader ref={ref}>
            {console.log(entry)}
            {inView &&
              <Typewriter
                onInit={(typewriter) => {
                  typewriter
                    .changeDelay(60)
                    .typeString("Projects")
                    .callFunction(state => state.elements.cursor.style.display = "none")
                    // .callFunction(state => state.elements.container.style.backgroundSize = "100% 3px")
                    .start()
                }}
              />
            }
          </SectionHeader>
        )}
      </InView>
    </ProjectsContainer>
  )
}

const ProjectsContainer = styled.section`
  width: 100%;
  height: 100vh;

  color: white;
  font-size: 3em;
`

const SectionHeader = styled.h3`
  padding: 1em 0 0 1em;
  font-weight: 400;
  width: fit-content;

  & div {
    background: linear-gradient(0deg, white, white) bottom center no-repeat;
    background-size: 0px 3px;
    transition: background-size 500ms;
    background-position: center bottom;
    padding-bottom: 0.1em;
  }
`

export default Projects
